1	//! Session manager for goal-scoped browser sessions.
2	//!
3	//! Each session wraps a [`CdpBackend`] (Chromium instance) and is
4	//! identified by a UUID. Sessions are organized by goal — not by tab —
5	//! and share the same goal state store.
6	
7	use std::collections::HashMap;
8	use std::sync::Arc;
9	use std::time::Duration;
10	
11	use ans_cdp::CdpBackend;
12	use ans_core::backend::{BrowserBackend, BrowserError, ImageFormat, PageState};
13	use ans_stealth::StealthConfig;
14	use ans_core::distill::{DistillMode, DistilledPage};
15	use ans_core::session::{Action, ActionOutcome, SessionStatus};
16	use tokio::sync::RwLock;
17	use tracing;
18	use uuid::Uuid;
19	
20	/// Handle to an active browser session.
21	pub struct SessionHandle {
22	    pub session_id: Uuid,
23	    pub goal_id: Uuid,
24	    pub backend: CdpBackend,
25	    pub current_url: String,
26	    pub status: SessionStatus,
27	}
28	
29	/// Thread-safe session registry.
30	///
31	/// Cloning shares the underlying `Arc<RwLock<>>` — all references
32	/// see the same sessions.
33	#[derive(Clone)]
34	pub struct SessionManager {
35	    sessions: Arc<RwLock<HashMap<Uuid, SessionHandle>>>,
36	}
37	
38	impl Default for SessionManager {
39	    fn default() -> Self {
40	        Self::new()
41	    }
42	}
43	
44	impl SessionManager {
45	    #[must_use] 
46	    pub fn new() -> Self {
47	        Self {
48	            sessions: Arc::new(RwLock::new(HashMap::new())),
49	        }
50	    }
51	
52	    /// Create a new session by launching a Chromium instance.
53	    /// If `start_url` is provided, navigate to it immediately.
54	    pub async fn create(
55	        &self,
56	        goal_id: Uuid,
57	        start_url: Option<String>,
58	    ) -> Result<Uuid, BrowserError> {
59	        let session_id = Uuid::new_v4();
60	        tracing::info!(%session_id, %goal_id, "Creating session");
61	
62	        let backend = CdpBackend::launch(Some(StealthConfig::standard())).await?;
63	
64	        if let Some(url) = &start_url {
65	            let _ = backend
66	                .navigate(url, Duration::from_secs(30))
67	                .await
68	                .map(|state| {
69	                    tracing::info!(url = %state.url, "Session started at URL");
70	                });
71	        }
72	
73	        let handle = SessionHandle {
74	            session_id,
75	            goal_id,
76	            backend,
77	            current_url: start_url.unwrap_or_else(|| "about:blank".into()),
78	            status: SessionStatus::Idle,
79	        };
80	
81	        self.sessions.write().await.insert(session_id, handle);
82	
83	        Ok(session_id)
84	    }
85	
86	    /// Close a session and kill its Chromium process.
87	    pub async fn close(&self, session_id: Uuid) -> Result<(), BrowserError> {
88	        tracing::info!(%session_id, "Closing session");
89	        let handle = self.sessions.write().await.remove(&session_id);
90	        if let Some(handle) = handle {
91	            handle.backend.close().await?;
92	        }
93	        Ok(())
94	    }
95	
96	    /// Close all active sessions.
97	    pub async fn close_all(&self) {
98	        let ids: Vec<Uuid> = self.sessions.read().await.keys().copied().collect();
99	        for id in ids {
100	            let _ = self.close(id).await;
101	        }
102	        tracing::info!("All sessions closed");
103	    }
104	
105	    /// Execute an action on a session.
106	    pub async fn execute_action(
107	        &self,
108	        session_id: Uuid,
109	        action: &Action,
110	    ) -> Result<ActionOutcome, BrowserError> {
111	        let sessions = self.sessions.read().await;
112	        let handle = sessions
113	            .get(&session_id)
114	            .ok_or(BrowserError::BrowserClosed)?;
115	
116	        let outcome = match action.action_type {
117	            ans_core::session::ActionType::Click => {
118	                let selector = action
119	                    .selector
120	                    .as_deref()
121	                    .ok_or_else(|| BrowserError::SelectorNotFound("missing selector".into()))?;
122	                handle.backend.click(selector).await?
123	            }
124	            ans_core::session::ActionType::Type => {
125	                let selector = action
126	                    .selector
127	                    .as_deref()
128	                    .ok_or_else(|| BrowserError::SelectorNotFound("missing selector".into()))?;
129	                let text = action.value.as_deref().unwrap_or("");
130	                handle.backend.type_text(selector, text).await?
131	            }
132	            ans_core::session::ActionType::Scroll => {
133	                let pixels = action.value.as_deref().and_then(|v| v.parse().ok());
134	                let selector = action.selector.as_deref();
135	                handle.backend.scroll(pixels, selector).await?
136	            }
137	            ans_core::session::ActionType::Select => {
138	                let selector = action
139	                    .selector
140	                    .as_deref()
141	                    .ok_or_else(|| BrowserError::SelectorNotFound("missing selector".into()))?;
142	                let value = action.value.as_deref().unwrap_or("");
143	                handle.backend.select_option(selector, value).await?
144	            }
145	            ans_core::session::ActionType::Navigate => {
146	                let url = action
147	                    .value
148	                    .as_deref()
149	                    .ok_or_else(|| BrowserError::CdpProtocol("missing URL".into()))?;
150	                let state = handle
151	                    .backend
152	                    .navigate(url, Duration::from_secs(30))
153	                    .await?;
154	                ActionOutcome {
155	                    success: true,
156	                    error_message: None,
157	                    execution_time_ms: 0,
158	                    page_url_after: Some(state.url),
159	                    dom_changed: false,
160	                }
161	            }
162	            ans_core::session::ActionType::Wait => {
163	                let ms = action
164	                    .value
165	                    .as_deref()
166	                    .and_then(|v| v.parse().ok())
167	                    .unwrap_or(1000u64);
168	                tokio::time::sleep(Duration::from_millis(ms)).await;
169	                ActionOutcome {
170	                    success: true,
171	                    error_message: None,
172	                    execution_time_ms: ms,
173	                    page_url_after: None,
174	                    dom_changed: false,
175	                }
176	            }
177	            ans_core::session::ActionType::Submit => {
178	                // Submit is typically handled as a click on a submit button
179	                // or pressing Enter. Evaluate a JS submit on the form.
180	                let selector = action.selector.as_deref().unwrap_or("form");
181	                let result = handle
182	                    .backend
183	                    .execute_script(&format!(
184	                        "(function(){{var f=document.querySelector('{}');if(f){{f.submit();return'ok'}}return'not found'}})()",
185	                        escape_for_js(selector)
186	                    ))
187	                    .await?;
188	                ActionOutcome {
189	                    success: result.contains("ok"),
190	                    error_message: if result.contains("ok") {
191	                        None
192	                    } else {
193	                        Some("form not found".into())
194	                    },
195	                    execution_time_ms: 0,
196	                    page_url_after: None,
197	                    dom_changed: true,
198	                }
199	            }
200	            ans_core::session::ActionType::Screenshot => {
201	                let _bytes = handle
202	                    .backend
203	                    .capture_screenshot(ans_core::backend::ImageFormat::Png, false)
204	                    .await?;
205	                ActionOutcome {
206	                    success: true,
207	                    error_message: None,
208	                    execution_time_ms: 0,
209	                    page_url_after: None,
210	                    dom_changed: false,
211	                }
212	            }
213	        };
214	
215	        Ok(outcome)
216	    }
217	
218	    /// Navigate a session to a URL.
219	    pub async fn navigate(&self, session_id: Uuid, url: &str) -> Result<PageState, BrowserError> {
220	        let sessions = self.sessions.read().await;
221	        let handle = sessions
222	            .get(&session_id)
223	            .ok_or(BrowserError::BrowserClosed)?;
224	
225	        handle.backend.navigate(url, Duration::from_secs(30)).await
226	    }
227	
228	    /// Distill the DOM in a session's current page.
229	    pub async fn get_distilled_dom(
230	        &self,
231	        session_id: Uuid,
232	        mode: DistillMode,
233	    ) -> Result<DistilledPage, BrowserError> {
234	        let sessions = self.sessions.read().await;
235	        let handle = sessions
236	            .get(&session_id)
237	            .ok_or(BrowserError::BrowserClosed)?;
238	        handle.backend.get_distilled_dom(mode).await
239	    }
240	
241	    /// Capture a screenshot from a session's current page.
242	    pub async fn capture_screenshot(
243	        &self,
244	        session_id: Uuid,
245	        format: ImageFormat,
246	        full_page: bool,
247	    ) -> Result<Vec<u8>, BrowserError> {
248	        let sessions = self.sessions.read().await;
249	        let handle = sessions
250	            .get(&session_id)
251	            .ok_or(BrowserError::BrowserClosed)?;
252	        handle.backend.capture_screenshot(format, full_page).await
253	    }
254	
255	    /// Get the number of active sessions.
256	    #[must_use] 
257	    pub fn session_count(&self) -> usize {
258	        self.sessions.try_read().map_or(0, |g| g.len())
259	    }
260	
261	    /// Get the current URL for a session without fetching DOM.
262	    pub async fn get_url(&self, session_id: Uuid) -> Option<String> {
263	        let sessions = self.sessions.read().await;
264	        sessions.get(&session_id).map(|h| h.current_url.clone())
265	    }
266	}
267	
268	fn escape_for_js(s: &str) -> String {
269	    s.replace('\\', "\\\\")
270	        .replace('\'', "\\'")
271	        .replace('\n', "\\n")
272	}
