1	//! gRPC server implementing the `AgentNervousSystem` service.
2	//!
3	//! Binds to loopback:50051. Only the Python nerves process and the
4	//! TypeScript dashboard (via envoy) connect here. External agents
5	//! go through the Layer 1 gateway on port 50052.
6	
7	use std::net::SocketAddr;
8	use std::sync::Arc;
9	
10	use ans_core::metrics::Metrics;
11	use ans_proto::ans::agent_nervous_system_server::AgentNervousSystem;
12	use ans_proto::ans::{
13	    ActionCheckRequest, ActionCheckResponse, ActionResult, BudgetConfig, BudgetConfigRequest,
14	    BudgetStatus, BudgetStatusRequest, CloseSessionRequest, CreateGoalRequest,
15	    CreateSessionRequest, DiffReport, DiffRequest, DistilledDom, DistractionList,
16	    DistractionRequest, DomRequest, Empty, ExecuteActionRequest, GoalState, GoalStateRequest,
17	    HealthStatus, InjectionScanRequest, InjectionScanResult, NavigateRequest, PageState,
18	    ProgressUpdate, QueryBestActionsRequest, RoutedSignal, ScoredActionList, ScreenshotRequest,
19	    ScreenshotResponse, SearchRequest, Session, SessionRequest, StoreScoreRequest,
20	    StoreScoreResponse, SubmitReportsRequest,
21	};
22	use tonic::{transport::Server, Request, Response, Status};
23	use tracing;
24	use uuid::Uuid;
25	
26	use ans_core::backend::ImageFormat;
27	use ans_core::distill::DistillMode;
28	use ans_core::signal::{EyeName, EyeReportContent};
29	
30	use ans_goal::GoalManager;
31	
32	use tokio_stream::{wrappers::BroadcastStream, StreamExt};
33	
34	use ans_signal::SignalRouter;
35	
36	use crate::session::SessionManager;
37	use crate::subscriber::{EventBus, EyeReportEvent};
38	
39	// ── Public API ───────────────────────────────────────────────────────
40	
41	/// The gRPC server. Created once at daemon startup, runs until shutdown.
42	pub struct IpcServer {
43	    sessions: SessionManager,
44	    goals: GoalManager,
45	    events: Arc<EventBus>,
46	    decisions: ans_storage::DecisionStore,
47	    budget: std::sync::Arc<tokio::sync::Mutex<ans_budget::BudgetTracker>>,
48	    signal_router: SignalRouter,
49	    metrics: Arc<Metrics>,
50	    nerves_dir: Option<std::path::PathBuf>,
51	}
52	
53	impl IpcServer {
54	    #[must_use]
55	    pub fn new() -> Self {
56	        Self {
57	            sessions: SessionManager::new(),
58	            goals: GoalManager::new(),
59	            events: Arc::new(EventBus::new()),
60	            decisions: ans_storage::DecisionStore::new(),
61	            budget: std::sync::Arc::new(tokio::sync::Mutex::new(
62	                ans_budget::BudgetTracker::default(),
63	            )),
64	            signal_router: SignalRouter::new(),
65	            metrics: Arc::new(Metrics::new()),
66	            nerves_dir: None,
67	        }
68	    }
69	
70	    #[must_use]
71	    pub fn with_nerves_dir(mut self, dir: std::path::PathBuf) -> Self {
72	        self.nerves_dir = Some(dir);
73	        self
74	    }
75	
76	    /// New with a shared metrics handle (from gateway).
77	    #[must_use]
78	    pub fn with_metrics(metrics: Arc<Metrics>) -> Self {
79	        Self {
80	            sessions: SessionManager::new(),
81	            goals: GoalManager::new(),
82	            events: Arc::new(EventBus::new()),
83	            decisions: ans_storage::DecisionStore::new(),
84	            budget: std::sync::Arc::new(tokio::sync::Mutex::new(
85	                ans_budget::BudgetTracker::default(),
86	            )),
87	            signal_router: SignalRouter::new(),
88	            metrics,
89	            nerves_dir: None,
90	        }
91	    }
92	
93	    /// Convert into a tonic service, useful for integration testing.
94	    pub fn into_tonic_service(
95	        self,
96	    ) -> generated::AgentNervousSystemServer<AgentNervousSystemServer> {
97	        let svc = AgentNervousSystemServer {
98	            sessions: self.sessions,
99	            goals: self.goals,
100	            events: self.events,
101	            decisions: self.decisions,
102	            budget: self.budget,
103	            signal_router: self.signal_router,
104	            metrics: self.metrics,
105	            nerves_dir: self.nerves_dir,
106	        };
107	        generated::AgentNervousSystemServer::new(svc)
108	    }
109	
110	    /// Start the gRPC server and block until shutdown signal received.
111	    pub async fn serve(self, addr: SocketAddr) -> Result<(), Box<dyn std::error::Error>> {
112	        let svc = AgentNervousSystemServer {
113	            sessions: self.sessions,
114	            goals: self.goals,
115	            events: self.events,
116	            decisions: self.decisions,
117	            budget: self.budget,
118	            signal_router: self.signal_router,
119	            metrics: self.metrics,
120	            nerves_dir: self.nerves_dir,
121	        };
122	
123	        tracing::info!("gRPC server starting on {}", addr);
124	
125	        Server::builder()
126	            .add_service(generated::AgentNervousSystemServer::new(svc))
127	            .serve_with_shutdown(addr, async {
128	                let _ = tokio::signal::ctrl_c().await;
129	                tracing::info!("Shutdown signal received");
130	            })
131	            .await?;
132	
133	        Ok(())
134	    }
135	}
136	
137	impl Default for IpcServer {
138	    fn default() -> Self {
139	        Self::new()
140	    }
141	}
