143	// ── Tonic service implementation ─────────────────────────────────────
144	
145	pub struct AgentNervousSystemServer {
146	    sessions: SessionManager,
147	    goals: GoalManager,
148	    #[allow(dead_code)]
149	    events: Arc<EventBus>,
150	    decisions: ans_storage::DecisionStore,
151	    budget: std::sync::Arc<tokio::sync::Mutex<ans_budget::BudgetTracker>>,
152	    signal_router: SignalRouter,
153	    metrics: Arc<Metrics>,
154	    nerves_dir: Option<std::path::PathBuf>,
155	}
156	
157	// Import the generated server trait module alias
158	use ans_proto::ans::agent_nervous_system_server as generated;
159	
160	#[tonic::async_trait]
161	impl AgentNervousSystem for AgentNervousSystemServer {
162	    // ── Session Management ──────────────────────────────────────────
163	
164	    async fn create_session(
165	        &self,
166	        request: Request<CreateSessionRequest>,
167	    ) -> Result<Response<Session>, Status> {
168	        let req = request.into_inner();
169	        let goal_id = parse_uuid(&req.goal_id, "goal_id")?;
170	        let start_url = optional_string(&req.start_url);
171	
172	        let session_id = self
173	            .sessions
174	            .create(goal_id, start_url)
175	            .await
176	            .map_err(|e| Status::internal(e.to_string()))?;
177	
178	        let now = now_epoch_ms();
179	        self.metrics.inc_sessions(1);
180	
181	        Ok(Response::new(Session {
182	            session_id: session_id.to_string(),
183	            goal_id: req.goal_id,
184	            status: "idle".into(),
185	            current_page: None,
186	            created_at: now,
187	            last_activity_at: now,
188	        }))
189	    }
190	
191	    async fn close_session(
192	        &self,
193	        request: Request<CloseSessionRequest>,
194	    ) -> Result<Response<Empty>, Status> {
195	        let req = request.into_inner();
196	        let session_id = parse_uuid(&req.session_id, "session_id")?;
197	        self.sessions
198	            .close(session_id)
199	            .await
200	            .map_err(|e| Status::internal(e.to_string()))?;
201	        self.metrics.inc_sessions(-1);
202	        Ok(Response::new(Empty {}))
203	    }
204	
205	    async fn navigate(
206	        &self,
207	        request: Request<NavigateRequest>,
208	    ) -> Result<Response<PageState>, Status> {
209	        let req = request.into_inner();
210	        let session_id = parse_uuid(&req.session_id, "session_id")?;
211	
212	        let state = self
213	            .sessions
214	            .navigate(session_id, &req.url)
215	            .await
216	            .map_err(|e| Status::internal(e.to_string()))?;
217	
218	        Ok(Response::new(PageState {
219	            url: state.url,
220	            title: state.title,
221	            loaded: state.loaded,
222	            dom_node_count: state.dom_node_count as i64,
223	            visible_text: state.visible_text,
224	            timestamp: state.timestamp.timestamp_millis(),
225	        }))
226	    }
227	
228	    async fn execute_action(
229	        &self,
230	        request: Request<ExecuteActionRequest>,
231	    ) -> Result<Response<ActionResult>, Status> {
232	        let req = request.into_inner();
233	        let session_id = parse_uuid(&req.session_id, "session_id")?;
234	
235	        let proto_action = req
236	            .action
237	            .ok_or_else(|| Status::invalid_argument("action is required"))?;
238	
239	        let action = proto_to_core_action(&proto_action)?;
240	
241	        let outcome = self
242	            .sessions
243	            .execute_action(session_id, &action)
244	            .await
245	            .map_err(|e| Status::internal(e.to_string()))?;
246	
247	        self.metrics.inc_actions();
248	        if !outcome.success {
249	            self.metrics.inc_errors();
250	        }
251	
252	        Ok(Response::new(ActionResult {
253	            success: outcome.success,
254	            error_message: outcome.error_message.unwrap_or_default(),
255	            new_state: None,
256	            diff: None,
257	            execution_time_ms: outcome.execution_time_ms as i64,
258	        }))
259	    }
260	
261	    // ── Perception ───────────────────────────────────────────────────
262	
263	    async fn get_distilled_dom(
264	        &self,
265	        request: Request<DomRequest>,
266	    ) -> Result<Response<DistilledDom>, Status> {
267	        let req = request.into_inner();
268	        let session_id = parse_uuid(&req.session_id, "session_id")?;
269	        let mode = parse_distill_mode(&req.mode)?;
270	
271	        let page = self
272	            .sessions
273	            .get_distilled_dom(session_id, mode)
274	            .await
275	            .map_err(|e| Status::internal(e.to_string()))?;
276	
277	        self.metrics.inc_dom_requests();
278	
279	        Ok(Response::new(
280	            ans_distill::serialization::distilled_page_to_proto(&page),
281	        ))
282	    }
283	
284	    async fn capture_screenshot(
285	        &self,
286	        request: Request<ScreenshotRequest>,
287	    ) -> Result<Response<ScreenshotResponse>, Status> {
288	        let req = request.into_inner();
289	        let session_id = parse_uuid(&req.session_id, "session_id")?;
290	
291	        let format = match req.format.as_str() {
292	            "jpeg" => ImageFormat::Jpeg {
293	                quality: req.quality.clamp(1, 100) as u8,
294	            },
295	            _ => ImageFormat::Png,
296	        };
297	
298	        let bytes = self
299	            .sessions
300	            .capture_screenshot(session_id, format, req.full_page)
301	            .await
302	            .map_err(|e| Status::internal(e.to_string()))?;
303	
304	        self.metrics.inc_screenshots();
305	
306	        Ok(Response::new(ScreenshotResponse {
307	            success: true,
308	            size_bytes: bytes.len() as i64,
309	            width: 0,
310	            height: 0,
311	            format: req.format,
312	            data: bytes,
313	            arrow_shm_key: String::new(),
314	        }))
315	    }
316	
317	    async fn compute_diff(
318	        &self,
319	        request: Request<DiffRequest>,
320	    ) -> Result<Response<DiffReport>, Status> {
321	        let req = request.into_inner();
322	        let before = req
323	            .before
324	            .ok_or_else(|| Status::invalid_argument("before is required"))?;
325	        let after = req
326	            .after
327	            .ok_or_else(|| Status::invalid_argument("after is required"))?;
328	
329	        let before_page = ans_distill::serialization::proto_to_distilled_page(&before);
330	        let after_page = ans_distill::serialization::proto_to_distilled_page(&after);
331	
332	        let differ = ans_diff::PageDiffer;
333	        let output = differ.diff(&before_page, &after_page);
334	
335	        Ok(Response::new(DiffReport {
336	            before_url: before_page.url,
337	            after_url: after_page.url,
338	            is_same_page: output.is_same_page,
339	            added: output
340	                .added
341	                .into_iter()
342	                .map(|c| ans_proto::ans::ElementChange {
343	                    tag: c.tag,
344	                    text: c.text,
345	                    selector: c.selector,
346	                    index: c.index,
347	                })
348	                .collect(),
349	            removed: output
350	                .removed
351	                .into_iter()
352	                .map(|c| ans_proto::ans::ElementChange {
353	                    tag: c.tag,
354	                    text: c.text,
355	                    selector: c.selector,
356	                    index: c.index,
357	                })
358	                .collect(),
359	            modified: output
360	                .modified
361	                .into_iter()
362	                .map(|m| ans_proto::ans::ElementModification {
363	                    selector: m.selector,
364	                    attribute_name: m.attribute_name,
365	                    old_value: m.old_value,
366	                    new_value: m.new_value,
367	                })
368	                .collect(),
369	            visual_diff_percentage: output.visual_diff_pct,
370	            summary: output.summary,
371	        }))
372	    }
373	
374	    // ── Goal State ──────────────────────────────────────────────────
375	
376	    async fn create_goal(
377	        &self,
378	        request: Request<CreateGoalRequest>,
379	    ) -> Result<Response<GoalState>, Status> {
380	        let req = request.into_inner();
381	        let state = self
382	            .goals
383	            .create_goal(&req.description, &req.context, req.max_steps as u32)
384	            .map_err(|e| Status::internal(e.to_string()))?;
385	
386	        self.metrics.inc_goals(1);
387	
388	        // Spawn Python AgentLoop in background
389	        let goal_id = state.goal_id.to_string();
390	        let goal_uuid = state.goal_id;
391	        let description = state.description.clone();
392	        let nerves_dir = self.nerves_dir.clone();
393	        let goals = self.goals.clone();
394	        tokio::spawn(async move {
395	            // Auto-detect venv Python relative to nerves_dir
396	            let python = if let Some(ref dir) = nerves_dir {
397	                let venv_python = dir.join(".venv").join("Scripts").join("python.exe");
398	                if venv_python.exists() {
399	                    venv_python
400	                } else {
401	                    let unix_venv = dir.join(".venv").join("bin").join("python");
402	                    if unix_venv.exists() { unix_venv } else { std::path::PathBuf::from("python") }
403	                }
404	            } else {
405	                std::path::PathBuf::from("python")
406	            };
407	
408	            let mut cmd = tokio::process::Command::new(&python);
409	            cmd.args(["-m", "ans_nerves", "run", "--goal-id", &goal_id, &description])
410	                .kill_on_drop(true);
411	            if let Some(ref dir) = nerves_dir {
412	                cmd.current_dir(dir);
413	            }
414	            match cmd.output().await {
415	                Ok(output) => {
416	                    if output.status.success() {
417	                        tracing::info!(%goal_id, "Python AgentLoop completed");
418	                    } else {
419	                        let stderr = String::from_utf8_lossy(&output.stderr);
420	                        tracing::error!(%goal_id, %stderr, "Python AgentLoop failed");
421	                        let _ = goals.update_progress(goal_uuid, 0.0, ans_core::goal::GoalStatus::Failed);
422	                    }
423	                }
424	                Err(e) => {
425	                    tracing::error!(%goal_id, error=%e, "Failed to spawn Python AgentLoop");
426	                    let _ = goals.update_progress(goal_uuid, 0.0, ans_core::goal::GoalStatus::Failed);
427	                }
428	            }
429	        });
430	
431	        Ok(Response::new(ans_goal::serialization::goal_state_to_proto(
432	            &state,
433	        )))
434	    }
