896	/// Convert a proto [`ans_proto::ans::EyeReport`] to core [`ans_core::signal::EyeReport`].
897	/// Returns `None` if the `eye_name` is unrecognized or the content is missing.
898	fn proto_to_core_eye_report(
899	    proto: &ans_proto::ans::EyeReport,
900	) -> Option<ans_core::signal::EyeReport> {
901	    use ans_proto::ans::eye_report::Content;
902	
903	    let eye_name = match proto.eye_name.as_str() {
904	        "dom_reader" => EyeName::DomReader,
905	        "vision" => EyeName::Vision,
906	        "page_diff" => EyeName::PageDiff,
907	        "goal_verifier" => EyeName::GoalVerifier,
908	        "error_detector" => EyeName::ErrorDetector,
909	        _ => return None,
910	    };
911	
912	    let content = match &proto.content {
913	        Some(Content::Dom(dom)) => EyeReportContent::DomReport {
914	            elements: vec![],
915	            interactive: vec![],
916	            mode: dom
917	                .dom
918	                .as_ref()
919	                .map_or(DistillMode::AllFields, |d| match d.mode.as_str() {
920	                    "text_only" => DistillMode::TextOnly,
921	                    "input_fields" => DistillMode::InputFields,
922	                    _ => DistillMode::AllFields,
923	                }),
924	        },
925	        Some(Content::Vision(v)) => EyeReportContent::VisionReport {
926	            visible_elements: v.visible_elements.clone(),
927	            overlays: v.overlays.clone(),
928	            blocked_regions: v.blocked_regions.clone(),
929	            page_type: v.page_type.clone(),
930	            anomalies: v.anomalies.clone(),
931	            raw_response: v.raw_response.clone(),
932	        },
933	        Some(Content::Diff(d)) => {
934	            let diff_report = d.diff.as_ref();
935	            EyeReportContent::DiffReport {
936	                added: diff_report.map_or(vec![], |r| {
937	                    r.added.iter().map(|e| e.selector.clone()).collect()
938	                }),
939	                removed: diff_report.map_or(vec![], |r| {
940	                    r.removed.iter().map(|e| e.selector.clone()).collect()
941	                }),
942	                modified: diff_report.map_or(vec![], |r| {
943	                    r.modified.iter().map(|m| m.selector.clone()).collect()
944	                }),
945	                visual_diff_pct: diff_report.map_or(0.0, |r| r.visual_diff_percentage),
946	                summary: diff_report.map_or(String::new(), |r| r.summary.clone()),
947	            }
948	        }
949	        Some(Content::Verification(v)) => EyeReportContent::Verification {
950	            sub_goal_advanced: v.criteria_status == "met",
951	            confidence: v.confidence,
952	            reasoning: v.reasoning.clone(),
953	            criteria_status: v.criteria_status.clone(),
954	        },
955	        Some(Content::Error(e)) => EyeReportContent::ErrorReport {
956	            failure_type: e.failure_type.clone(),
957	            description: e.description.clone(),
958	            recovery_actions: e.recovery_actions.clone(),
959	            should_retry: e.should_retry,
960	            max_retries: e.max_retries as u32,
961	        },
962	        None => return None,
963	    };
964	
965	    Some(ans_core::signal::EyeReport {
966	        eye_name,
967	        timestamp: chrono::Utc::now(),
968	        confidence: proto.confidence,
969	        goal_relevance: proto.goal_relevance,
970	        content,
971	    })
972	}
