974	/// Format the oneof eye report content into a readable string.
975	fn format_eye_content(content: Option<&ans_proto::ans::eye_report::Content>) -> String {
976	    use ans_proto::ans::eye_report::Content;
977	    match content {
978	        Some(Content::Dom(dom)) => {
979	            format!(
980	                "DOM: {} elements, {} interactive",
981	                dom.dom.as_ref().map_or(0, |d| d.elements.len() as i32),
982	                dom.focused_elements.len()
983	            )
984	        }
985	        Some(Content::Vision(v)) => {
986	            format!(
987	                "Vision: {} visible, {} overlays, type={}",
988	                v.visible_elements.len(),
989	                v.overlays.len(),
990	                v.page_type
991	            )
992	        }
993	        Some(Content::Diff(d)) => {
994	            format!(
995	                "Diff: {}% visual change",
996	                d.diff.as_ref().map_or(0.0, |r| r.visual_diff_percentage)
997	            )
998	        }
999	        Some(Content::Verification(v)) => {
1000	            format!(
1001	                "Verify: {} (confidence={:.0}%)",
1002	                v.criteria_status,
1003	                v.confidence * 100.0
1004	            )
1005	        }
1006	        Some(Content::Error(e)) => {
1007	            format!("Error: {} — {}", e.failure_type, e.description)
1008	        }
1009	        None => "no content".into(),
1010	    }
1011	}
