1	//! Chromium process lifecycle management.
2	//!
3	//! Spawns headless Chromium with `--remote-debugging-port`, monitors
4	//! its health, and guarantees cleanup on drop.
5	//!
6	//! # Safety invariant
7	//!
8	//! When [`ChromiumProcess`] is dropped, the child process MUST be killed.
9	//! Zombie Chromium processes are a hard bug.
10	
11	use std::net::TcpListener;
12	use std::path::PathBuf;
13	use std::time::Duration;
14	
15	use ans_stealth::StealthConfig;
16	use tokio::process::{Child, Command};
17	use tracing;
18	
19	/// Owns a running Chromium child process.
20	///
21	/// Created via [`ChromiumProcess::launch`]. On drop, the child is killed
22	/// and the temporary user-data directory is removed.
23	pub struct ChromiumProcess {
24	    child: Option<Child>,
25	    debug_port: u16,
26	    debug_url: String,
27	    /// WebSocket URL for the first page target (not the browser endpoint).
28	    page_url: String,
29	    user_data_dir: PathBuf,
30	}
31	
32	impl ChromiumProcess {
33	    /// Launch a headless Chromium instance with remote debugging enabled.
34	    ///
35	    /// Finds the Chromium executable on PATH (or common install locations),
36	    /// allocates an ephemeral port, spawns the process, and waits for the
37	    /// debug WebSocket URL to become available.
38	    ///
39	    /// When `stealth` is provided, anti-detection flags are merged into
40	    /// the launch command.
41	    pub async fn launch(stealth: Option<&StealthConfig>) -> Result<Self, LaunchError> {
42	        let exe = find_chromium()?;
43	        let port = allocate_port()?;
44	        let user_data_dir =
45	            std::env::temp_dir().join(format!("ans-chromium-{}", uuid::Uuid::new_v4()));
46	
47	        std::fs::create_dir_all(&user_data_dir)?;
48	
49	        tracing::info!(
50	            exe = %exe.display(),
51	            port = port,
52	            user_data_dir = %user_data_dir.display(),
53	            stealth = stealth.is_some(),
54	            "Launching Chromium"
55	        );
56	
57	        let mut cmd = Command::new(&exe);
58	        cmd.arg("--headless=new")
59	            .arg(format!("--remote-debugging-port={port}"))
60	            .arg(format!("--user-data-dir={}", user_data_dir.display()))
61	            .arg("--no-sandbox")
62	            .arg("--disable-gpu")
63	            .arg("--disable-dev-shm-usage")
64	            .arg("--disable-extensions")
65	            .arg("--disable-background-networking")
66	            .arg("--disable-sync")
67	            .arg("--disable-translate")
68	            .arg("--disable-default-apps")
69	            .arg("--hide-scrollbars")
70	            .arg("--metrics-recording-only")
71	            .arg("--mute-audio")
72	            .arg("--no-first-run")
73	            .arg("--window-size=1280,720")
74	            .arg("about:blank");
75	
76	        // Merge stealth anti-detection flags
77	        if let Some(config) = stealth {
78	            for flag in config.chrome_flags() {
79	                cmd.arg(flag);
80	            }
81	        }
82	
83	        let child = cmd
84	            .kill_on_drop(true)
85	            .spawn()
86	            .map_err(|e| LaunchError::SpawnFailed {
87	                exe: exe.clone(),
88	                source: e,
89	            })?;
90	
91	        let debug_url = discover_debug_url(port).await?;
92	        let page_url = discover_page_url(port).await?;
93	
94	        tracing::info!(%debug_url, %page_url, "Chromium ready");
95	
96	        Ok(Self {
97	            child: Some(child),
98	            debug_port: port,
99	            debug_url,
100	            page_url,
101	            user_data_dir,
102	        })
103	    }
104	
105	    /// The browser-level WebSocket URL (for Target.* commands only).
106	    #[must_use] 
107	    pub fn debug_url(&self) -> &str {
108	        &self.debug_url
109	    }
110	
111	    /// The page-level WebSocket URL (for Page.*, DOM.*, Runtime.* commands).
112	    #[must_use] 
113	    pub fn page_url(&self) -> &str {
114	        &self.page_url
115	    }
116	
117	    /// The TCP port Chromium is listening on for CDP connections.
118	    #[must_use] 
119	    pub const fn debug_port(&self) -> u16 {
120	        self.debug_port
121	    }
122	}
123	
124	impl Drop for ChromiumProcess {
125	    fn drop(&mut self) {
126	        if let Some(mut child) = self.child.take() {
127	            tracing::debug!(pid = child.id(), "Killing Chromium child process");
128	            // kill_on_drop(true) handles this, but explicitly kill for clarity
129	            if let Err(e) = child.start_kill() {
130	                tracing::warn!(pid = child.id(), ?e, "Failed to kill Chromium process");
131	            }
132	        }
133	        if self.user_data_dir.exists() {
134	            if let Err(e) = std::fs::remove_dir_all(&self.user_data_dir) {
135	                tracing::warn!(dir = %self.user_data_dir.display(), ?e, "Failed to remove temp user-data dir");
136	            }
137	        }
138	    }
139	}
140	
141	// ── Helpers ──────────────────────────────────────────────────────────
142	
143	/// Allocate an ephemeral TCP port by binding to port 0 and reading the assigned port.
144	fn allocate_port() -> Result<u16, LaunchError> {
145	    let listener = TcpListener::bind("127.0.0.1:0")?;
146	    let port = listener.local_addr()?.port();
147	    drop(listener);
148	    Ok(port)
149	}
150	
151	/// Discover the CDP WebSocket debug URL by polling Chromium's HTTP endpoint.
152	async fn discover_debug_url(port: u16) -> Result<String, LaunchError> {
153	    let url = format!("http://127.0.0.1:{port}/json/version");
154	    let client = reqwest::Client::new();
155	
156	    // Chromium takes a moment to start. Retry with backoff.
157	    let mut attempts = 0;
158	    loop {
159	        match client
160	            .get(&url)
161	            .timeout(Duration::from_secs(5))
162	            .send()
163	            .await
164	        {
165	            Ok(resp) => {
166	                if resp.status().is_success() {
167	                    let json: serde_json::Value = resp.json().await?;
168	                    return json["webSocketDebuggerUrl"]
169	                        .as_str()
170	                        .map(String::from)
171	                        .ok_or(LaunchError::DebugUrlNotFound);
172	                }
173	            }
174	            Err(_) if attempts < 20 => {
175	                attempts += 1;
176	                tokio::time::sleep(Duration::from_millis(250)).await;
177	            }
178	            Err(e) => {
179	                return Err(LaunchError::HttpConnectionFailed { url, source: e });
180	            }
181	        }
182	    }
183	}
184	
185	/// Discover the page-level CDP WebSocket URL by polling Chromium's `/json` endpoint.
186	///
187	/// The `/json/version` endpoint returns the browser-level WebSocket URL which only
188	/// supports `Browser.*` and `Target.*` domains. For `Page.*`, `DOM.*`, and `Runtime.*`
189	/// commands, we must connect to a specific page target's WebSocket URL.
190	async fn discover_page_url(port: u16) -> Result<String, LaunchError> {
191	    let url = format!("http://127.0.0.1:{port}/json");
192	    let client = reqwest::Client::new();
193	
194	    let mut attempts = 0;
195	    loop {
196	        match client
197	            .get(&url)
198	            .timeout(Duration::from_secs(5))
199	            .send()
200	            .await
201	        {
202	            Ok(resp) => {
203	                if resp.status().is_success() {
204	                    let targets: Vec<serde_json::Value> = resp.json().await?;
205	                    // Find the first "page" type target (not "background_page", "worker", etc.)
206	                    for target in &targets {
207	                        let target_type = target["type"].as_str().unwrap_or("");
208	                        if target_type == "page" {
209	                            if let Some(page_url) =
210	                                target["webSocketDebuggerUrl"].as_str()
211	                            {
212	                                return Ok(page_url.to_string());
213	                            }
214	                        }
215	                    }
216	                    // If no explicit "page" type, fall back to the first target with a debug URL
217	                    for target in &targets {
218	                        if let Some(page_url) = target["webSocketDebuggerUrl"].as_str() {
219	                            return Ok(page_url.to_string());
220	                        }
221	                    }
222	                    return Err(LaunchError::DebugUrlNotFound);
223	                }
224	            }
225	            Err(_) if attempts < 20 => {
226	                attempts += 1;
227	                tokio::time::sleep(Duration::from_millis(250)).await;
228	            }
229	            Err(e) => {
230	                return Err(LaunchError::HttpConnectionFailed { url, source: e });
231	            }
232	        }
233	    }
234	}
235	
236	/// Locate a Chromium/Chrome executable on the system.
237	fn find_chromium() -> Result<PathBuf, LaunchError> {
238	    let exe_names: &[&str] = if cfg!(target_os = "windows") {
239	        &["chromium.exe", "chrome.exe"]
240	    } else {
241	        &["chromium", "chromium-browser", "chrome", "google-chrome"]
242	    };
243	
244	    // 1. Search PATH
245	    if let Ok(path_var) = std::env::var("PATH") {
246	        for dir in std::env::split_paths(&path_var) {
247	            for name in exe_names {
248	                let candidate = dir.join(name);
249	                if candidate.is_file() {
250	                    tracing::debug!(path = %candidate.display(), "Found Chromium on PATH");
251	                    return Ok(candidate);
252	                }
253	            }
254	        }
255	    }
256	
257	    // 2. macOS: check Application bundles
258	    #[cfg(target_os = "macos")]
259	    {
260	        let mac_paths = [
261	            "/Applications/Chromium.app/Contents/MacOS/Chromium",
262	            "/Applications/Google Chrome.app/Contents/MacOS/Google Chrome",
263	        ];
264	        for p in &mac_paths {
265	            let pb = PathBuf::from(p);
266	            if pb.is_file() {
267	                return Ok(pb);
268	            }
269	        }
270	    }
271	
272	    // 3. Windows: check common install directories
273	    #[cfg(target_os = "windows")]
274	    {
275	        let locals = [
276	            std::env::var("LOCALAPPDATA"),
277	            std::env::var("ProgramFiles"),
278	            std::env::var("ProgramFiles(x86)"),
279	        ];
280	        for local_var in locals.iter().flatten() {
281	            let candidates = [
282	                PathBuf::from(local_var).join("Chromium\\Application\\chrome.exe"),
283	                PathBuf::from(local_var).join("Google\\Chrome\\Application\\chrome.exe"),
284	            ];
285	            for p in &candidates {
286	                if p.is_file() {
287	                    tracing::debug!(path = %p.display(), "Found Chromium via install path");
288	                    return Ok(p.clone());
289	                }
290	            }
291	        }
292	    }
293	
294	    Err(LaunchError::ChromiumNotFound)
295	}
296	
297	// ── Error type ───────────────────────────────────────────────────────
298	
299	#[derive(Debug, thiserror::Error)]
300	pub enum LaunchError {
301	    #[error("chromium executable not found on PATH or common install locations")]
302	    ChromiumNotFound,
303	
304	    #[error("failed to allocate ephemeral port: {0}")]
305	    PortAllocation(#[from] std::io::Error),
306	
307	    #[error("failed to spawn {exe}: {source}")]
308	    SpawnFailed {
309	        exe: PathBuf,
310	        #[source]
311	        source: std::io::Error,
312	    },
313	
314	    #[error("webSocketDebuggerUrl not found in /json/version response")]
315	    DebugUrlNotFound,
316	
317	    #[error("HTTP request to {url} failed: {source}")]
318	    HttpConnectionFailed {
319	        url: String,
320	        #[source]
321	        source: reqwest::Error,
322	    },
323	
324	    #[error("HTTP response parse error: {0}")]
325	    HttpParse(#[from] reqwest::Error),
326	}
