1	//! Goal lifecycle manager.
2	//!
3	//! Creates goals, decomposes them into sub-goals with a basic heuristic
4	//! (Python coordinator over gRPC is Phase 4), tracks progress in the
5	//! shared [`GoalStateStore`].
6	
7	use std::collections::HashMap;
8	
9	use ans_core::goal::{GoalContext, GoalState, GoalStatus, SubGoal, SubGoalStatus};
10	use uuid::Uuid;
11	
12	use crate::store::{GoalStateStore, GoalStoreError};
13	
14	/// Manages the lifecycle of all active goals.
15	///
16	/// Cloning shares the underlying store (Arc pointer copy).
17	#[derive(Clone)]
18	pub struct GoalManager {
19	    store: GoalStateStore,
20	}
21	
22	impl GoalManager {
23	    /// Create a new, empty goal manager.
24	    #[must_use] 
25	    pub fn new() -> Self {
26	        Self {
27	            store: GoalStateStore::new(256),
28	        }
29	    }
30	
31	    /// Create a goal and decompose into sub-goals.
32	    ///
33	    /// Decomposition uses a keyword-based heuristic. Full LLM decomposition
34	    /// via the Python coordinator is deferred to Phase 4.
35	    pub fn create_goal(
36	        &self,
37	        description: &str,
38	        context: &HashMap<String, String>,
39	        _max_steps: u32,
40	    ) -> Result<GoalState, GoalStoreError> {
41	        let goal_id = Uuid::new_v4();
42	        let sub_goals = decompose_heuristic(description);
43	        let url = context.get("current_url").cloned();
44	
45	        let total = sub_goals.len() as f32;
46	        let done = sub_goals
47	            .iter()
48	            .filter(|s| s.status == SubGoalStatus::Done)
49	            .count() as f32;
50	        let progress = if total > 0.0 { done / total } else { 0.0 };
51	
52	        let status = if progress >= 1.0 {
53	            GoalStatus::Completed
54	        } else {
55	            GoalStatus::Active
56	        };
57	
58	        let state = GoalState {
59	            goal_id,
60	            description: description.to_string(),
61	            status,
62	            progress,
63	            sub_goals,
64	            context: GoalContext {
65	                current_url: url,
66	                last_action: None,
67	                last_observation: None,
68	                intent_embedding: vec![],
69	                distraction_count: 0,
70	            },
71	            created_at: chrono::Utc::now(),
72	            updated_at: chrono::Utc::now(),
73	        };
74	
75	        self.store.insert(state.clone())?;
76	        Ok(state)
77	    }
78	
79	    /// Retrieve a goal state by ID.
80	    #[must_use] 
81	    pub fn get_goal_state(&self, goal_id: &Uuid) -> Option<GoalState> {
82	        self.store.get(goal_id)
83	    }
84	
85	    /// Update progress and status for an existing goal.
86	    pub fn update_progress(
87	        &self,
88	        goal_id: Uuid,
89	        progress: f32,
90	        status: GoalStatus,
91	    ) -> Result<GoalState, GoalStoreError> {
92	        self.store.update_progress(goal_id, progress, status)
93	    }
94	
95	    /// List all active goal IDs.
96	    #[must_use] 
97	    pub fn list_ids(&self) -> Vec<Uuid> {
98	        self.store.list_ids()
99	    }
100	
101	    /// Number of active goals.
102	    #[allow(dead_code)]
103	    #[must_use] 
104	    pub fn active_count(&self) -> usize {
105	        self.store.len()
106	    }
107	
108	    /// Underlying store reference — for subscribers.
109	    #[must_use] 
110	    pub const fn store(&self) -> &GoalStateStore {
111	        &self.store
112	    }
113	
114	    /// Subscribe to goal state change notifications.
115	    #[must_use] 
116	    pub fn subscribe(
117	        &self,
118	    ) -> tokio::sync::broadcast::Receiver<crate::store::GoalStateNotification> {
119	        self.store.subscribe()
120	    }
121	}
122	
123	impl Default for GoalManager {
124	    fn default() -> Self {
125	        Self::new()
126	    }
127	}
128	
129	// ── Heuristic decomposition ──────────────────────────────────────────
130	
131	/// Action verbs mapped to their typical pre-requisites and verification steps.
132	const NAVIGATION_VERBS: &[&str] = &[
133	    "go to", "navigate", "visit", "open", "browse", "find", "search",
134	];
135	
136	const INPUT_VERBS: &[&str] = &[
137	    "fill", "type", "enter", "input", "write", "set", "select", "choose", "pick", "check", "click",
138	    "submit",
139	];
140	
141	const EXTRACTION_VERBS: &[&str] = &[
142	    "read", "extract", "get", "fetch", "download", "scrape", "collect", "copy", "export", "save",
143	];
144	
145	fn decompose_heuristic(description: &str) -> Vec<SubGoal> {
146	    let lower = description.to_lowercase();
147	    let has_navigation = NAVIGATION_VERBS.iter().any(|v| lower.contains(v));
148	    let has_input = INPUT_VERBS.iter().any(|v| lower.contains(v));
149	    let has_extraction = EXTRACTION_VERBS.iter().any(|v| lower.contains(v));
150	
151	    let mut sub_goals = Vec::with_capacity(3);
152	    #[allow(clippy::useless_let_if_seq)]
153	    let mut prev_id: Option<Uuid> = None;
154	
155	    // 1. Navigation phase
156	    if has_navigation {
157	        let id = Uuid::new_v4();
158	        sub_goals.push(SubGoal {
159	            id,
160	            description: format!("Navigate to the target page for: {description}"),
161	            success_criteria: vec!["Page loaded successfully".into()],
162	            depends_on: vec![],
163	            status: SubGoalStatus::Active,
164	        });
165	        prev_id = Some(id);
166	    }
167	
168	    // 2. Interaction phase
169	    if has_input {
170	        let id = Uuid::new_v4();
171	        let deps: Vec<Uuid> = prev_id.into_iter().collect();
172	        sub_goals.push(SubGoal {
173	            id,
174	            description: format!("Interact with the page to complete: {description}"),
175	            success_criteria: vec!["All required fields populated".into()],
176	            depends_on: deps,
177	            status: SubGoalStatus::Pending,
178	        });
179	        prev_id = Some(id);
180	    }
181	
182	    // 3. Verification / extraction phase
183	    if has_extraction || !sub_goals.is_empty() {
184	        let id = Uuid::new_v4();
185	        let deps: Vec<Uuid> = prev_id.into_iter().collect();
186	        sub_goals.push(SubGoal {
187	            id,
188	            description: format!("Verify result for: {description}"),
189	            success_criteria: vec!["Expected outcome confirmed".into()],
190	            depends_on: deps,
191	            status: SubGoalStatus::Pending,
192	        });
193	    }
194	
195	    // Fallback — single sub-goal for unrecognized descriptions
196	    if sub_goals.is_empty() {
197	        sub_goals.push(SubGoal {
198	            id: Uuid::new_v4(),
199	            description: format!("Complete: {description}"),
200	            success_criteria: vec!["Task completed successfully".into()],
201	            depends_on: vec![],
202	            status: SubGoalStatus::Active,
203	        });
204	    }
205	
206	    sub_goals
207	}
208	
