1	//! Proto ↔ Core type conversion for goal state types.
2	//!
3	//! The proto layer uses strings for IDs/enums (transport-safe).
4	//! The core layer uses proper Rust types (Uuid, enums).
5	
6	use ans_core::goal::{GoalContext, GoalState, GoalStatus, SubGoal, SubGoalStatus};
7	use ans_proto::ans;
8	use uuid::Uuid;
9	
10	/// Core `GoalState` → proto `GoalState`.
11	pub fn goal_state_to_proto(state: &GoalState) -> ans::GoalState {
12	    ans::GoalState {
13	        goal_id: state.goal_id.to_string(),
14	        description: state.description.clone(),
15	        status: goal_status_to_str(state.status).into(),
16	        progress: state.progress,
17	        sub_goals: state.sub_goals.iter().map(sub_goal_to_proto).collect(),
18	        context: Some(goal_context_to_proto(&state.context)),
19	        created_at: state.created_at.timestamp_millis(),
20	        updated_at: state.updated_at.timestamp_millis(),
21	    }
22	}
23	
24	/// Proto `GoalState` → core `GoalState`.
25	pub fn proto_to_goal_state(proto: &ans::GoalState) -> Option<GoalState> {
26	    let goal_id = Uuid::parse_str(&proto.goal_id).ok()?;
27	    Some(GoalState {
28	        goal_id,
29	        description: proto.description.clone(),
30	        status: str_to_goal_status(&proto.status),
31	        progress: proto.progress,
32	        sub_goals: proto.sub_goals.iter().map(proto_to_sub_goal).collect(),
33	        context: proto
34	            .context
35	            .as_ref()
36	            .map(proto_to_goal_context)
37	            .unwrap_or_default(),
38	        created_at: chrono::DateTime::from_timestamp_millis(proto.created_at)
39	            .unwrap_or_else(chrono::Utc::now),
40	        updated_at: chrono::DateTime::from_timestamp_millis(proto.updated_at)
41	            .unwrap_or_else(chrono::Utc::now),
42	    })
43	}
44	
45	// ── SubGoal ──────────────────────────────────────────────────────────
46	
47	fn sub_goal_to_proto(sg: &SubGoal) -> ans::SubGoal {
48	    ans::SubGoal {
49	        id: sg.id.to_string(),
50	        description: sg.description.clone(),
51	        success_criteria: sg.success_criteria.clone(),
52	        depends_on: sg.depends_on.iter().map(std::string::ToString::to_string).collect(),
53	        status: sub_goal_status_to_str(sg.status).into(),
54	    }
55	}
56	
57	fn proto_to_sub_goal(proto: &ans::SubGoal) -> SubGoal {
58	    SubGoal {
59	        id: Uuid::parse_str(&proto.id).unwrap_or_else(|_| Uuid::new_v4()),
60	        description: proto.description.clone(),
61	        success_criteria: proto.success_criteria.clone(),
62	        depends_on: proto
63	            .depends_on
64	            .iter()
65	            .filter_map(|id| Uuid::parse_str(id).ok())
66	            .collect(),
67	        status: str_to_sub_goal_status(&proto.status),
68	    }
69	}
70	
71	// ── GoalContext ──────────────────────────────────────────────────────
72	
73	fn goal_context_to_proto(ctx: &GoalContext) -> ans::GoalContext {
74	    ans::GoalContext {
75	        current_url: ctx.current_url.clone().unwrap_or_default(),
76	        last_action: ctx.last_action.clone().unwrap_or_default(),
77	        last_observation: ctx.last_observation.clone().unwrap_or_default(),
78	        intent_embedding: ctx.intent_embedding.clone(),
79	        distraction_count: ctx.distraction_count,
80	    }
81	}
82	
83	fn proto_to_goal_context(proto: &ans::GoalContext) -> GoalContext {
84	    GoalContext {
85	        current_url: if proto.current_url.is_empty() {
86	            None
87	        } else {
88	            Some(proto.current_url.clone())
89	        },
90	        last_action: if proto.last_action.is_empty() {
91	            None
92	        } else {
93	            Some(proto.last_action.clone())
94	        },
95	        last_observation: if proto.last_observation.is_empty() {
96	            None
97	        } else {
98	            Some(proto.last_observation.clone())
99	        },
100	        intent_embedding: proto.intent_embedding.clone(),
101	        distraction_count: proto.distraction_count,
102	    }
103	}
