152	    #[test]
153	    fn test_roundtrip_goal_state() {
154	        let ctx = GoalContext {
155	            current_url: Some("https://example.com".into()),
156	            ..Default::default()
157	        };
158	
159	        let state = GoalState {
160	            goal_id: Uuid::new_v4(),
161	            description: "Book a flight to NYC".into(),
162	            status: GoalStatus::Active,
163	            progress: 0.3,
164	            sub_goals: vec![SubGoal {
165	                id: Uuid::new_v4(),
166	                description: "Navigate to airline site".into(),
167	                success_criteria: vec!["Page loads".into()],
168	                depends_on: vec![],
169	                status: SubGoalStatus::Done,
170	            }],
171	            context: ctx,
172	            created_at: chrono::Utc::now(),
173	            updated_at: chrono::Utc::now(),
174	        };
175	
176	        let proto = goal_state_to_proto(&state);
177	        let roundtripped = proto_to_goal_state(&proto).unwrap();
178	
179	        assert_eq!(roundtripped.goal_id, state.goal_id);
180	        assert_eq!(roundtripped.description, state.description);
181	        assert_eq!(roundtripped.status, state.status);
182	        assert_eq!(roundtripped.sub_goals.len(), 1);
183	        assert_eq!(
184	            roundtripped.sub_goals[0].description,
185	            "Navigate to airline site"
186	        );
187	        assert_eq!(roundtripped.sub_goals[0].status, SubGoalStatus::Done);
188	        assert_eq!(
189	            roundtripped.context.current_url,
190	            Some("https://example.com".into())
191	        );
192	    }
