194	    #[test]
195	    fn test_status_strings() {
196	        assert_eq!(str_to_goal_status("active"), GoalStatus::Active);
197	        assert_eq!(str_to_goal_status("completed"), GoalStatus::Completed);
198	        assert_eq!(str_to_goal_status("failed"), GoalStatus::Failed);
199	        assert_eq!(str_to_goal_status("blocked"), GoalStatus::Blocked);
200	        assert_eq!(str_to_goal_status("garbage"), GoalStatus::Pending);
201	    }
202	}
